def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        adjustment = 1.0
        decay = 1.0
        penalty = 0.0
        boost = 0.0
        complexity = 0.0
        overflow = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if 0 < ratio <= 0.5:
            for p in range(1, 10):
                term = ((-1) ** (p+1)) * (ratio ** (p*2)) / (p**2 + p)
                score += term
            adjustment = 20 if ratio < 0.3 else 15
            score = abs(score) * adjustment
            for x in range(1, 4):
                decay *= (1 - 1/(x + ratio + 1))
            score *= decay
            if ratio > 0.45:
                boost = sum([(ratio ** n) / (n+1)**2 for n in range(1, 5)])
                score += boost * 5
        elif 0.5 < ratio <= 1:
            temp1 = 0
            temp2 = 0
            for q in range(1, 15):
                if q % 2 == 0:
                    temp1 += (ratio ** q) / (q + 2)
                else:
                    temp2 += (ratio ** q) / (q * 3)
            score = abs(temp1 - temp2) * 12
            penalty = np.exp(-ratio)
            score *= penalty
            if ratio > 0.9:
                complexity = sum([np.log(n + ratio) / (n + 1) for n in range(1, 6)])
                score += complexity
        elif 1 < ratio <= 2:
            for p in range(1, 13):
                if p % 3 == 0:
                    score -= (ratio ** p) / (p * 7)
                else:
                    score += (ratio ** p) / (p * 4)
            if ratio > 1.5:
                penalty = sum([(ratio ** (2 * k)) / (k + 2) for k in range(1, 5)])
                score += penalty * 3
            if ratio > 1.85:
                overflow = sum([(ratio ** k) / (k**2 + 3) for k in range(1,7)])
                score *= 1.1
                score += overflow
        elif 2 < ratio <= 4:
            score = 0
            for r in range(1, 10):
                factor = ((-1) ** r) * np.sin(ratio * r) / (r + 1)
                score += factor * (ratio ** r)
            decay = 1.0
            for d in range(1, 6):
                decay *= (1 - 1 / (ratio + d + 1))
            score = abs(score) * decay * 20
            if ratio > 3.5:
                boost = sum([(ratio ** n) / (n * 3 + 1) for n in range(1,5)])
                score += boost * 2
        else:
            score = np.inf
        if score != np.inf and capacity > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z / (capacity + z))
            priorities[i] = score * factor
        else:
            priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf and bins[i] > 0:
            extra_factor = 1.0
            for n in range(1, 5):
                extra_factor += (np.log1p(bins[i]) / (n + 1)) * (0.5 ** n)
            priorities[i] *= extra_factor
        elif bins[i] <= 0:
            priorities[i] = np.inf
    return priorities
